{
  "title": "Science Exam for Lower Classes",
   "description": "A comprehensive science exam covering basic concepts for lower classes",
   "timeLimit": 60,
   "passingScore": 70,
   "sections": [
       {
           "name": "A",
           "description": "Multiple Choice questions",
           "questions": [
               {
                   "text": "What is the process by which plants make their own food?",
                   "type": "multiple-choice",
                   "points": 2,
                   "difficulty": "easy",
                   "options": [
                       {"text": "Respiration", "isCorrect": false, "letter": "A"},
                       {"text": "Photosynthesis", "isCorrect": true, "letter": "B"},
                       {"text": "Decomposition", "isCorrect": false, "letter": "C"},
                       {"text": "Fermentation", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "B",
                   "explanation": "Photosynthesis is the process by which plants, algae, and some bacteria convert light energy, usually from the sun, into chemical energy stored in glucose. Respiration is the process by which cells generate energy from glucose, decomposition is the process of breaking down dead organisms, and fermentation is a process of converting glucose into energy without using oxygen."
               }
           ]
       },
       {
           "name": "B",
           "description": "Open Ended questions",
           "questions": [
               {
                   "text": "Describe the water cycle and its importance in our ecosystem",
                   "type": "open-ended",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "The water cycle, also known as the hydrologic cycle, is the continuous process by which water is circulated between the Earth and the atmosphere. It involves the movement of water in three phases: liquid, solid (ice), and gas (water vapor). The process begins with evaporation, where water from the oceans, lakes, and rivers is heated by the sun, turning it into water vapor. This vapor rises into the atmosphere and cools, condensing into clouds. When the clouds become saturated, they release their water content in the form of precipitation (rain, snow, sleet, or hail). Once the precipitation reaches the ground, it can flow over the surface as runoff, soak into the soil as infiltration, or be absorbed by plants as transpiration. The water cycle is crucial for our ecosystem because it distributes freshwater around the planet, regulates Earth's climate, and supports plant growth. Without the water cycle, life as we know it would not be possible.",
                   "gradingCriteria": [
                       "Defines the water cycle (2 marks)",
                       "Explains the process of evaporation, condensation, and precipitation (3 marks)",
                       "Describes the importance of the water cycle in the ecosystem (3 marks)",
                       "Provides examples of the water cycle in nature (2 marks)"
                   ]
               },
               {
                   "text": "What are the main components of an ecosystem and how do they interact?",
                   "type": "open-ended",
                   "points": 10,
                   "difficulty": "hard",
                   "correctAnswer": "An ecosystem consists of living organisms (biotic factors) and non-living components (abiotic factors) that interact with each other in a specific environment. The biotic factors include producers (plants, algae), consumers (herbivores, carnivores, omnivores), and decomposers (bacteria, fungi). The abiotic factors include light, temperature, water, soil, and air. These components interact through various processes such as photosynthesis, respiration, decomposition, and nutrient cycling. For example, plants (producers) use sunlight, water, and carbon dioxide to produce glucose, which is then consumed by herbivores. The herbivores are then consumed by carnivores, and the energy is transferred from one trophic level to the next. Decomposers break down dead organisms, releasing nutrients back into the soil, which are then absorbed by plants. This complex network of interactions maintains the balance and stability of the ecosystem.",
                   "gradingCriteria": [
                       "Identifies the main components of an ecosystem (2 marks)",
                       "Explains the interactions between biotic and abiotic factors (3 marks)",
                       "Describes the processes of energy transfer and nutrient cycling (3 marks)",
                       "Provides examples of ecosystems and their components (2 marks)"
                   ]
               }
           ]
       },
       {
           "name": "C",
           "description": "True / False questions",
           "questions": [
               {
                   "text": "The Earth's atmosphere is composed mostly of oxygen",
                   "type": "true-false",
                   "points": 1,
                   "difficulty": "easy",
                   "options": [
                       {"text": "True", "isCorrect": false, "letter": "A"},
                       {"text": "False", "isCorrect": true, "letter": "B"}
                   ],
                   "correctAnswer": "False",
                   "explanation": "The Earth's atmosphere is actually composed mostly of nitrogen (about 78%) and oxygen (about 21%)."
               }
           ]
       },
       {
           "name": "D",
           "description": "Short Answer questions",
           "questions": [
               {
                   "text": "What is the function of the roots in a plant?",
                   "type": "short-answer",
                   "points": 3,
                   "difficulty": "easy",
                   "correctAnswer": "The roots of a plant are responsible for absorbing water and nutrients from the soil. They also anchor the plant in place, providing stability and support. Additionally, roots can store food and nutrients for the plant, allowing it to survive during times of drought or other stress.",
                   "keyPoints": [
                       "Absorbing water and nutrients",
                       "Anchoring the plant",
                       "Storing food and nutrients"
                   ]
               }
           ]
       },
       {
           "name": "E",
           "description": "Fill in Blank questions",
           "questions": [
               {
                   "text": "The process of plants releasing water vapor into the air is called _______",
                   "type": "fill-in-blank",
                   "points": 1,
                   "difficulty": "easy",
                   "correctAnswer": "transpiration",
                   "explanation": "Transpiration is the process by which plants release water vapor into the air through their leaves.",
                   "acceptableAnswers": [
                       "transpiration",
                       "evapotranspiration"
                   ]
               }
           ]
       },
       {
           "name": "F",
           "description": "Matching questions",
           "questions": [
               {
                   "text": "Match the following types of rocks with their descriptions",
                   "type": "matching",
                   "points": 3,
                   "difficulty": "medium",
                   "leftItems": [
                       "Igneous",
                       "Sedimentary",
                       "Metamorphic"
                   ],
                   "rightItems": [
                       "Formed from the cooling and solidification of magma",
                       "Formed from the compression and cementation of sediments",
                       "Formed from the alteration of existing rocks under high pressure and temperature"
                   ],
                   "correctAnswer": [
                       {"left": 0, "right": 0},
                       {"left": 1, "right": 1},
                       {"left": 2, "right": 2}
                   ],
                   "explanation": "Igneous rocks are formed from the cooling and solidification of magma, sedimentary rocks are formed from the compression and cementation of sediments, and metamorphic rocks are formed from the alteration of existing rocks under high pressure and temperature.",
                   "marks": 3
               }
           ]
       },
       {
           "name": "G",
           "description": "Ordering questions",
           "questions": [
               {
                   "text": "Arrange the following stages of the water cycle in order",
                   "type": "ordering",
                   "points": 4,
                   "difficulty": "medium",
                   "items": [
                       "Evaporation",
                       "Condensation",
                       "Precipitation",
                       "Runoff"
                   ],
                   "correctAnswer": [
                       0,
                       1,
                       2,
                       3
                   ],
                   "explanation": "The correct order of the water cycle is: evaporation, condensation, precipitation, and runoff.",
                   "marks": 4
               }
           ]
       }
   ]
}
